on_write:
let res = #{ action: "Allow" };
if !payload.contains("key") || !payload.contains("value") {
    res.action = "Reject";
    res.reason = "Missing key or value fields for KV paradigm";
}
res

on_read:
let res = #{ payload: payload };
if payload.key == query_key {
    res.match_found = true;
} else {
    res.match_found = false;
}
res
